const DOOR_ORDER = ["NOC", "LAB", "NOC-FES", "FES"];

function formatConductorChapa(value) {
  const text = String(value || "").trim();
  if (!text) return "";
  if (text.length === 5) return text;
  return `7${text.padStart(4, "0")}`;
}

function parseSequentialCenso(raw, { conductorPrefix = true } = {}) {
  return raw.trim()
    .split(/\s+/)
    .filter(Boolean)
    .map((value, index) => ({
      chapa: conductorPrefix ? formatConductorChapa(value) : String(value).padStart(5, "0"),
      sourceChapa: String(value),
      position: index + 1,
      displayPosition: index + 1
    }));
}

function parsePairCenso(raw) {
  const values = raw.trim().split(/\s+/).filter(Boolean);
  const result = [];

  for (let index = 0; index < values.length; index += 2) {
    const chapa = values[index];
    const sourcePosition = Number(values[index + 1]);
    if (!chapa || !Number.isFinite(sourcePosition)) continue;
    const position = result.length + 1;
    result.push({
      chapa: String(chapa).padStart(5, "0"),
      sourceChapa: String(chapa),
      sourcePosition,
      position,
      displayPosition: position
    });
  }

  return result;
}

